mapper.select:
SELECT
    su.id,
    su.username,
    su.real_name AS realName,
    su.phone,
    su.email,
    su.dept_id AS deptId,
    su.status,
    su.last_login_at AS lastLoginAt,
    su.create_time AS createTime
FROM sys_user su
WHERE su.deleted = 0

    AND (
        su.username LIKE CONCAT('%', #{request.keyword}, '%')
        OR su.real_name LIKE CONCAT('%', #{request.keyword}, '%')
    )


    AND su.status = #{request.status}


    AND su.dept_id = #{request.groupId}


    AND (
        su.dept_id = #{request.deptId}
        OR su.dept_id IN (
            SELECT id FROM sys_dept
            WHERE deleted = 0 AND parent_id = #{request.deptId}
        )
    )


    AND EXISTS (
        SELECT 1 FROM sys_user_role sur
        WHERE sur.user_id = su.id AND sur.role_id = #{request.roleId}
    )


    AND EXISTS (
        SELECT 1 FROM sys_user_role sur
        INNER JOIN sys_role sr ON sr.id = sur.role_id AND sr.deleted = 0
        WHERE sur.user_id = su.id AND sr.role_code = #{request.roleCode}
    )


    AND ${ew.sqlSegment}

ORDER BY su.create_time DESC
